class VideoPlayer:
    def __init__(self, video_streaming_service):
        self.video_streaming_service = video_streaming_service
        self.current_video = None
        self.current_time = 0
        self.playing = False

    def play_video(self, video_id):
        video = self.video_streaming_service.get_video(video_id)
        if video:
            self.current_video = video
            self.playing = True
            self.current_time = 0
        else:
            print("Video not found")

    def pause_video(self):
        if self.playing:
            self.playing = False
        else:
            print("Video is not playing")

    def resume_video(self):
        if not self.playing:
            self.playing = True
        else:
            print("Video is already playing")

    def skip_forwards(self, seconds):
        if self.playing:
            self.current_time += seconds
        else:
            print("Video is not playing")

    def skip_backwards(self, seconds):
        if self.playing:
            self.current_time -= seconds
            if self.current_time < 0:
                self.current_time = 0
        else:
            print("Video is not playing")

    def get_current_time(self):
        return self.current_time

