class VideoStreamingServer:
    def __init__(self, video_streaming_service):
        self.video_streaming_service = video_streaming_service

    def handle_request(self, request):
        if request["type"] == "play":
            video_id = request["video_id"]
            video_player = VideoPlayer(self.video_streaming_service)
            video_player.play_video(video_id)
            return {"status": "playing", "video_id": video_id}
        elif request["type"] == "pause":
            video_id = request["video_id"]
            video_player = VideoPlayer(self.video_streaming_service)
            video_player.pause_video()
            return {"status": "paused", "video_id": video_id}
        elif request["type"] == "resume":
            video_id = request["video_id"]
            video_player = VideoPlayer(self.video_streaming_service)
            video_player.resume_video()
            return {"status": "resumed", "video_id": video_id}
        elif request["type"] == "skip_forwards":
            video_id = request["video_id"]
            seconds = request["seconds"]
            video_player = VideoPlayer(self.video_streaming_service)
            video_player.skip_forwards(seconds)
            return {"status": "skipped_forwards", "video_id": video_id}
        elif request["type"] == "skip_backwards":
            video_id = request["video_id"]
            seconds = request["seconds"]
            video_player = VideoPlayer(self.video_streaming_service)
            video_player.skip_backwards(seconds)
            return {"status": "skipped_backwards", "video_id": video_id}
        elif request["type"] == "get_current_time":
            video_id = request["video_id"]
            video_player = VideoPlayer(self.video_streaming_service)
            return {"status": "current_time", "video_id": video_id, "current_time": video_player.get_current_time()}
        else:
            return {"status": "error", "message": "Invalid request"}

