import os
import threading
from flask import Flask, request, send_file, jsonify
from flask_sqlalchemy import SQLAlchemy
from werkzeug.utils import secure_filename
from pydub import AudioSegment
import ffmpeg

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///video_streaming.db'
db = SQLAlchemy(app)

class Video(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    title = db.Column(db.String(100), nullable=False)
    description = db.Column(db.String(200), nullable=False)
    filename = db.Column(db.String(100), nullable=False)
    resolution = db.Column(db.String(20), nullable=False)

    def __repr__(self):
        return f"Video('{self.title}', '{self.filename}', '{self.resolution}')"

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(20), unique=True, nullable=False)
    email = db.Column(db.String(120), unique=True, nullable=False)

    def __repr__(self):
        return f"User('{self.username}', '{self.email}')"

@app.route('/upload', methods=['POST'])
def upload_video():
    if request.method == 'POST':
        if 'file' not in request.files:
            return jsonify({'message': 'No file part'}), 400
        file = request.files['file']
        if file.filename == '':
            return jsonify({'message': 'No selected file'}), 400
        if file:
            filename = secure_filename(file.filename)
            file.save(os.path.join('uploads', filename))
            video = Video(title=request.form['title'], description=request.form['description'], filename=filename, resolution=request.form['resolution'])
            db.session.add(video)
            db.session.commit()
            return jsonify({'message': 'Video uploaded successfully'}), 200

@app.route('/videos', methods=['GET'])
def get_videos():
    videos = Video.query.all()
    output = []
    for video in videos:
        video_data = {'id': video.id, 'title': video.title, 'description': video.description, 'filename': video.filename, 'resolution': video.resolution}
        output.append(video_data)
    return jsonify({'videos': output}), 200

@app.route('/video/<int:video_id>', methods=['GET'])
def get_video(video_id):
    video = Video.query.get_or_404(video_id)
    return send_file(os.path.join('uploads', video.filename), as_attachment=True)

